from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, natural‑language sentence. Handles many known predicates with
    specific phrasing and falls back to a generic style for unknown ones.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to turn ordinal prefixes like '1st' into words
    _ordinal_map = {
        "1st": "first",
        "2nd": "second",
        "3rd": "third",
        "4th": "fourth",
        "5th": "fifth",
        "6th": "sixth",
        "7th": "seventh",
        "8th": "eighth",
        "9th": "ninth",
    }

    # Group phrases by subject to avoid repeating it
    subject_phrases: dict[str, list[str]] = {}

    for t in triples:
        s = t.subject
        p = t.predicate
        o = _clean(t.object)

        phrase = ""

        if p == "cityServed":
            phrase = f"serves the city of {o}"
        elif p == "location":
            phrase = f"is located in {o}"
        elif p == "country":
            phrase = f"is in {o}"
        elif p == "isPartOf":
            phrase = f"is part of {o}"
        elif p == "elevationAboveTheSeaLevel":
            phrase = f"lies at an elevation of {o} metres above sea level"
        elif p == "elevationAboveTheSeaLevelInFeet":
            phrase = f"lies at an elevation of {o} feet above sea level"
        elif p == "operatingOrganisation":
            phrase = f"is operated by {o}"
        elif p == "runwaySurfaceType":
            phrase = f"has a runway surface of {o}"
        elif p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            word = _ordinal_map.get(idx, idx.lower())
            phrase = f"has a {word} runway that is {o} feet long"
        elif p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            word = _ordinal_map.get(idx, idx.lower())
            phrase = f"has a {word} runway that is {o} metres long"
        elif p == "runwayName":
            phrase = f"has a runway named {o}"
        elif p == "runwayLength":
            phrase = f"has a runway length of {o} metres"
        else:
            # Generic fallback
            phrase = f"has {p} {o}"

        subject_phrases.setdefault(s, []).append(phrase)

    sentences: list[str] = []
    for subj, phs in subject_phrases.items():
        # Combine the phrases with commas and a final 'and'
        if len(phs) == 1:
            body = phs[0]
        else:
            body = ", ".join(phs[:-1]) + f", and {phs[-1]}"
        sentences.append(f"{subj}, {body}")

    # Join multiple subject sentences with a space
    final = ". ".join(sentences) + "."
    return final[0].upper() + final[1:]

# EVOLVE-BLOCK-END

